shape.script:
let handleAttraction = 3.5;

function getHandles(params) {
    let width = params.size.x;
    let height = params.size.y;
    let tail = params.tail;
    let r = Math.min(Math.max(0.0,params.cornerRadius),Math.min(width,height));
    let pointOffs = r * (1.0-0.552228474);
    let tailWidthHandle = null;

    if( Math.abs(tail.y) <= Math.abs(tail.x) ) {

        let minPos = -height + r
        let maxPos = height - r
        let tailHalfWidth = Math.min(params.tailWidth, maxPos - minPos) / 2;
        let tailPos = tail.y * handleAttraction;
        tailPos = Math.max(tailPos,minPos+tailHalfWidth);
        tailPos = Math.min(tailPos,maxPos-tailHalfWidth);

        if( tail.x < 0 ) {  // LEFT
            tailWidthHandle = {x:-width, y:tailPos+tailHalfWidth, axis:[0,1]};
        } else {            // RIGHT
            tailWidthHandle = {x:width, y:tailPos+tailHalfWidth, axis:[0,1]};
        }

    } else {

        let minPos = -width + r
        let maxPos = width - r
        let tailHalfWidth = Math.min(params.tailWidth, maxPos - minPos) / 2;
        let tailPos = tail.x * handleAttraction;
        tailPos = Math.max(tailPos,minPos+tailHalfWidth);
        tailPos = Math.min(tailPos,maxPos-tailHalfWidth);

        if( tail.y < 0 ) {  // TOP
            tailWidthHandle = {x:tailPos+tailHalfWidth, y:-height, axis:[1,0]};
        } else {            // BOTTOM
            tailWidthHandle = {x:tailPos+tailHalfWidth, y:height, axis:[1,0]};
        }

    }

    return {
        tw: tailWidthHandle,
        r: [-width + r, -height],
        t: params.tail,
        n: [0, -height],
        s: [0, height],
        e: [width, 0],
        w: [-width, 0],
        ne: [width, -height],
        se: [width, height],
        nw: [-width, -height],
        sw: [-width, height]
    }
}

function getPath(params) {
    let width = params.size.x;
    let height = params.size.y;
    let tail = params.tail;
    let r = Math.min(Math.max(0.0,params.cornerRadius),Math.min(width,height));
    let pointOffs = r * (1.0-0.552228474);
    let result = [

        // TOP SIDE
        {
            in: [-width + pointOffs, -height],
            p: [-width + r, -height]
        },
        // <-- Position for TOP tail (index 1)
        {
            p: [width - r, -height],
            out: [width-pointOffs, -height]
        },

        // RIGHT SIDE
        {
            in: [width, -height + pointOffs],
            p: [width, -height + r]
        },
        // <-- Position for RIGHT tail (index 3)
        {
            p: [width, height-r],
            out: [width, height - pointOffs]
        },

        // BOTTOM SIDE
        {
            in: [width-pointOffs, height],
            p: [width-r, height]
        },
        // <-- Position for BOTTOM tail (index 5)
        {
            p: [-width + r, height],
            out: [-width + pointOffs, height]
        },

        // LEFT SIDE
        {
            in: [-width, height-pointOffs],
            p: [-width, height-r]
        },
        // <-- Position for LEFT tail (index 7)
        {
            p: [-width, -height + r],
            out: [-width, -height + pointOffs]
        },


        {closed:true}
    ];

    if( Math.abs(tail.y) <= Math.abs(tail.x) ) {

        let minPos = -height + r
        let maxPos = height - r
        let tailHalfWidth = Math.min(params.tailWidth, maxPos - minPos) / 2;
        let tailPos = tail.y * handleAttraction;
        tailPos = Math.max(tailPos,minPos+tailHalfWidth);
        tailPos = Math.min(tailPos,maxPos-tailHalfWidth);

        if( tail.x < 0 ) {  // LEFT

            result.splice(7,0,
                [-width, tailPos+tailHalfWidth],
                [tail.x,tail.y],
                [-width, tailPos-tailHalfWidth]
            );

        } else {            // RIGHT

            result.splice(3,0,
                [width, tailPos-tailHalfWidth],
                [tail.x,tail.y],
                [width, tailPos+tailHalfWidth]
            );

        }

    } else {

        let minPos = -width + r
        let maxPos = width - r
        let tailHalfWidth = Math.min(params.tailWidth, maxPos - minPos) / 2;
        let tailPos = tail.x * handleAttraction;
        tailPos = Math.max(tailPos,minPos+tailHalfWidth);
        tailPos = Math.min(tailPos,maxPos-tailHalfWidth);

        if( tail.y < 0 ) {  // TOP

            result.splice(1,0,
                [tailPos-tailHalfWidth, -height],
                [tail.x,tail.y],
                [tailPos+tailHalfWidth, -height]
            )

        } else {            // BOTTOM

            result.splice(5,0,
                [tailPos+tailHalfWidth, height],
                [tail.x,tail.y],
                [tailPos-tailHalfWidth, height]
            )

        }

    }

    return result;

}
